// Headers und Body auslesen
const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || input;

// Headers case-insensitive lesen
const tenantId = (headers['x-tenant-id'] || headers['X-Tenant-ID'] || '').trim();
const apiKey = (headers['x-api-key'] || headers['X-API-Key'] || '').trim();

// Query aus Body
const query = (body.query || body.question || '').trim();
const sessionId = body.session_id || null;

// Validierung
if (!tenantId) throw new Error('X-Tenant-ID Header fehlt');
if (!apiKey) throw new Error('X-API-Key Header fehlt');
if (!query || query.length < 1) throw new Error('query oder question fehlt im Request Body');

return [{ json: { tenantId, apiKey, query, sessionId, startedAt: Date.now() } }];

// Tenant-Info mit ursprünglicher Anfrage zusammenführen
const tenant = $input.first().json;
const authData = $('Auth vorbereiten').first().json;

if (!tenant || !tenant.id) {
  throw new Error('Tenant-Authentifizierung fehlgeschlagen');
}

return [{ json: {
  tenantId: tenant.id,
  tenantName: tenant.name,
  tenantSlug: tenant.slug,
  query: authData.query,
  sessionId: authData.sessionId,
  startedAt: authData.startedAt
}}];

// Embedding-Array in PostgreSQL-Vector-Format umwandeln
const embedResult = $input.first().json;
const authQuery = $('Merge Auth + Query').first().json;

// /api/embed gibt { embeddings: [[...]] } zurück
const embeddingArray = embedResult.embeddings?.[0] || embedResult.embedding || [];

if (!Array.isArray(embeddingArray) || embeddingArray.length === 0) {
  throw new Error('Kein Embedding von Ollama erhalten: ' + JSON.stringify(embedResult));
}

if (embeddingArray.length !== 1024) {
  throw new Error(`Falsche Embedding-Dimension: ${embeddingArray.length} (erwartet: 1024)`);
}

// Format für PostgreSQL vector(1024): '[0.1, 0.2, ...]'
const vectorStr = '[' + embeddingArray.map(v => v.toFixed(8)).join(',') + ']';

return [{ json: {
  ...authQuery,
  vectorStr
}}];

// Chunks zu Kontext zusammenbauen
const chunks = $input.all().map(i => i.json);
const authQuery = $('Embedding formatieren').first().json;

// Kein Ergebnis: leeres Ergebnis zurückgeben (nicht stoppen)
const hasResults = chunks && chunks.length > 0 && chunks[0].chunk_id;

if (!hasResults) {
  return [{ json: {
    ...authQuery,
    context: '',
    sources: [],
    chunksUsed: 0,
    hasContext: false
  }}];
}

// Kontext-String aufbauen (max. 6000 Zeichen)
const MAX_CHARS = 6000;
let contextParts = [];
let totalChars = 0;

for (const chunk of chunks) {
  const part = `[Quelle: ${chunk.source_title || 'Dokument'} | Ähnlichkeit: ${(chunk.similarity * 100).toFixed(0)}%]\n${chunk.content}`;
  if (totalChars + part.length > MAX_CHARS) break;
  contextParts.push(part);
  totalChars += part.length;
}

const context = contextParts.join('\n\n---\n\n');

const sources = chunks.map(c => ({
  title: c.source_title || 'Unbekannt',
  type: c.source_type || 'text',
  similarity: Math.round((c.similarity || 0) * 100) / 100,
  chunk_index: c.chunk_index || 0
}));

return [{ json: {
  ...authQuery,
  context,
  sources,
  chunksUsed: contextParts.length,
  hasContext: true
}}];

// Ollama Chat-Anfrage mit this.helpers.httpRequest (fetch/crypto blockiert in n8n 2.9.4)
const data = $input.first().json;

const systemPrompt = data.hasContext
  ? `Du bist ein hilfreicher Kundenservice-Assistent von EPPCOM GmbH. ` +
    `Beantworte die folgende Frage NUR basierend auf dem Kontext unten. ` +
    `Wenn die Antwort nicht im Kontext ist, sage: "Dazu habe ich leider keine Information in meiner Wissensdatenbank." ` +
    `Antworte immer auf Deutsch, präzise und freundlich.\n\nKONTEXT:\n${data.context}`
  : `Du bist ein hilfreicher Kundenservice-Assistent von EPPCOM GmbH. ` +
    `Es wurden keine relevanten Dokumente zu dieser Frage gefunden. ` +
    `Erkläre das freundlich und schlage vor, die Frage anders zu formulieren oder direkt Kontakt aufzunehmen.`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://10.0.0.3:11434/api/chat',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'qwen3-nothink',
    stream: false,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: data.query }
    ],
    options: { temperature: 0.1, num_ctx: 4096 }
  }),
  json: false
});

const parsed = typeof response === 'string' ? JSON.parse(response) : response;

return [{ json: {
  ...data,
  rawAnswer: parsed.message?.content || '',
  evalCount: parsed.eval_count || 0,
  totalDuration: parsed.total_duration || 0
}}];

// <think>-Tags entfernen und Response formatieren
const data = $input.first().json;

let answer = (data.rawAnswer || '')
  .replace(/<think>[\s\S]*?<\/think>\s*/g, '')
  .trim();

// Fallback wenn Antwort leer
if (!answer) {
  answer = data.hasContext
    ? 'Es tut mir leid, ich konnte keine passende Antwort generieren. Bitte versuchen Sie es mit einer anderen Formulierung.'
    : 'Es wurden keine relevanten Informationen zu Ihrer Frage gefunden. Bitte kontaktieren Sie uns direkt.';
}

const totalMs = Date.now() - (data.startedAt || Date.now());
const evalDurationMs = Math.round((data.totalDuration || 0) / 1000000);

return [{ json: {
  answer,
  sources: data.sources || [],
  chunks_used: data.chunksUsed || 0,
  model: 'qwen3-nothink',
  tenant: data.tenantName || 'EPPCOM',
  session_id: data.sessionId,
  timing: {
    total_duration_ms: totalMs,
    eval_count: data.evalCount || 0
  }
}}];
